In the production account:use role accountadmin;create database ABC_CLONE clone ABC;create share ABC_SHARE;grant usage on database ABC_CLONE to share ABC_SHARE;alter share ABC_share add accounts = dev_account;
In the developer account:use role accountadmin;create database ABC_DEV FROM share prod_account.ABC_SHARE;grant imported privileges on database ABC_DEV to role developers;
